+fn parse_client_list_fields(line: &str) -> HashMap<String, String> {
+    line.split_whitespace()
+        .filter_map(|field| {
+            let (key, value) = field.split_once('=')?;
+            Some((key.to_string(), value.to_string()))
+        })
+        .collect()
+}
